import { forwardRef, useState } from "react";
import { cva, type VariantProps } from "class-variance-authority";
import { User } from "lucide-react";
import type { ComponentPropsWithoutRef, ReactNode } from "react";
import { cn } from "@/lib/utils";

const avatarFaceVariants = cva(
  "inline-flex shrink-0 items-center justify-center overflow-hidden bg-(--avatar-bg) font-medium text-(--avatar-fg)",
  {
    variants: {
      size: {
        xs: "size-(--avatar-xs-size) [font-size:var(--avatar-xs-font-size)] rounded-(--avatar-xs-radius)",
        sm: "size-(--avatar-sm-size) [font-size:var(--avatar-sm-font-size)] rounded-(--avatar-sm-radius)",
        md: "size-(--avatar-md-size) [font-size:var(--avatar-md-font-size)] rounded-(--avatar-md-radius)",
        lg: "size-(--avatar-lg-size) [font-size:var(--avatar-lg-font-size)] rounded-(--avatar-lg-radius)",
        xl: "size-(--avatar-xl-size) [font-size:var(--avatar-xl-font-size)] rounded-(--avatar-xl-radius)",
        "2xl":
          "size-(--avatar-2xl-size) [font-size:var(--avatar-2xl-font-size)] rounded-(--avatar-2xl-radius)",
        "3xl":
          "size-(--avatar-3xl-size) [font-size:var(--avatar-3xl-font-size)] rounded-(--avatar-3xl-radius)",
      },
      shape: {
        squircle: "",
        circle: "!rounded-full",
      },
    },
    defaultVariants: {
      size: "md",
      shape: "squircle",
    },
  },
);

const fallbackIconSizeClasses = {
  xs: "[width:var(--avatar-xs-icon-size)] [height:var(--avatar-xs-icon-size)]",
  sm: "[width:var(--avatar-sm-icon-size)] [height:var(--avatar-sm-icon-size)]",
  md: "[width:var(--avatar-md-icon-size)] [height:var(--avatar-md-icon-size)]",
  lg: "[width:var(--avatar-lg-icon-size)] [height:var(--avatar-lg-icon-size)]",
  xl: "[width:var(--avatar-xl-icon-size)] [height:var(--avatar-xl-icon-size)]",
  "2xl": "[width:var(--avatar-2xl-icon-size)] [height:var(--avatar-2xl-icon-size)]",
  "3xl": "[width:var(--avatar-3xl-icon-size)] [height:var(--avatar-3xl-icon-size)]",
} as const;

type AvatarSize = NonNullable<VariantProps<typeof avatarFaceVariants>["size"]>;
type AvatarShape = NonNullable<VariantProps<typeof avatarFaceVariants>["shape"]>;

export type AvatarProps = Omit<ComponentPropsWithoutRef<"span">, "children"> & {
  src?: string;
  alt?: string;
  fallback?: string;
  size?: AvatarSize;
  shape?: AvatarShape;
  /** Custom status indicator rendered over the avatar. Compose your own badge here. */
  status?: ReactNode;
};

export const Avatar = forwardRef<HTMLSpanElement, AvatarProps>(
  (
    {
      className,
      src = "",
      alt = "",
      fallback = "",
      size = "md",
      shape = "squircle",
      status,
      ...props
    },
    ref,
  ) => {
    const [imageError, setImageError] = useState(false);
    const showImage = Boolean(src) && !imageError;
    const initials = fallback.trim().slice(0, 2);
    const label = alt || initials || "User avatar";

    return (
      <span
        ref={ref}
        role="img"
        aria-label={label}
        data-size={size}
        data-shape={shape}
        className={cn("relative inline-flex shrink-0 select-none", className)}
        {...props}
      >
        <span className={avatarFaceVariants({ size, shape })}>
          {showImage ? (
            <img
              src={src}
              alt={alt}
              className="size-full object-cover"
              onError={() => {
                setImageError(true);
              }}
            />
          ) : initials ? (
            <span aria-hidden="true">{initials}</span>
          ) : (
            <User className={cn(fallbackIconSizeClasses[size], "text-(--color-muted-foreground)")} aria-hidden="true" />
          )}
        </span>
        {status}
      </span>
    );
  },
);

Avatar.displayName = "Avatar";

/* Avatar component tokens — override these to customise avatars. */
:root {
  /* Per-size dimensions */
  --avatar-xs-size: 16px;
  --avatar-sm-size: 20px;
  --avatar-md-size: 24px;
  --avatar-lg-size: 28px;
  --avatar-xl-size: 32px;
  --avatar-2xl-size: 40px;
  --avatar-3xl-size: 46px;

  /* Per-size squircle radii */
  --avatar-xs-radius: 4px;
  --avatar-sm-radius: 5px;
  --avatar-md-radius: 5px;
  --avatar-lg-radius: 6px;
  --avatar-xl-radius: 6px;
  --avatar-2xl-radius: 8px;
  --avatar-3xl-radius: 8px;

  /* Per-size initials font sizes */
  --avatar-xs-font-size: 11px;
  --avatar-sm-font-size: 13px;
  --avatar-md-font-size: 14px;
  --avatar-lg-font-size: 14px;
  --avatar-xl-font-size: 16px;
  --avatar-2xl-font-size: 18px;
  --avatar-3xl-font-size: 20px;

  /* Per-size fallback icon sizes */
  --avatar-xs-icon-size: 10px;
  --avatar-sm-icon-size: 12px;
  --avatar-md-icon-size: 14px;
  --avatar-lg-icon-size: 16px;
  --avatar-xl-icon-size: 18px;
  --avatar-2xl-icon-size: 22px;
  --avatar-3xl-icon-size: 24px;

  /* Surfaces */
  --avatar-bg: var(--color-muted);
  --avatar-fg: var(--color-foreground);
}

import { Avatar } from "./Avatar";
import { cn } from "@/lib/utils";

const overlapClasses = {
  xs: "-ml-(--avatar-group-overlap-xs)",
  sm: "-ml-(--avatar-group-overlap-sm)",
  md: "-ml-(--avatar-group-overlap-md)",
  lg: "-ml-(--avatar-group-overlap-lg)",
  xl: "-ml-(--avatar-group-overlap-xl)",
  "2xl": "-ml-(--avatar-group-overlap-2xl)",
  "3xl": "-ml-(--avatar-group-overlap-3xl)",
} as const;

const labelSizeClasses = {
  xs: "[font-size:var(--avatar-group-label-xs-font-size)]",
  sm: "[font-size:var(--avatar-group-label-sm-font-size)]",
  md: "[font-size:var(--avatar-group-label-md-font-size)]",
  lg: "[font-size:var(--avatar-group-label-lg-font-size)]",
  xl: "[font-size:var(--avatar-group-label-xl-font-size)]",
  "2xl": "[font-size:var(--avatar-group-label-2xl-font-size)]",
  "3xl": "[font-size:var(--avatar-group-label-3xl-font-size)]",
} as const;

const ringClass =
  "[&>span:first-child]:[box-shadow:0_0_0_var(--avatar-group-ring-width)_var(--avatar-group-ring)]";

type AvatarGroupSize = keyof typeof overlapClasses;

export type AvatarGroupItem = {
  src?: string;
  alt?: string;
  fallback?: string;
};

export type AvatarGroupProps = {
  items?: AvatarGroupItem[];
  max?: number;
  showCount?: boolean;
  count?: number;
  size?: AvatarGroupSize;
  className?: string;
};

export function AvatarGroup({
  items = [],
  max = 5,
  showCount = false,
  count = 0,
  size = "md",
  className,
}: AvatarGroupProps) {
  const visibleItems = items.slice(0, max);
  const overflowCount = items.length > max ? items.length - max : 0;
  const memberCount = count > 0 ? count : items.length;

  return (
    <div className={cn("inline-flex items-center gap-3", className)} data-size={size}>
      <div className="inline-flex items-center">
        {visibleItems.map((item, index) => (
          <Avatar
            key={`${item.src ?? item.fallback ?? "avatar"}-${index}`}
            src={item.src}
            alt={item.alt}
            fallback={item.fallback}
            size={size}
            shape="circle"
            className={cn(ringClass, index > 0 && overlapClasses[size])}
            style={{ zIndex: index + 1 }}
          />
        ))}
        {overflowCount > 0 ? (
          <Avatar
            fallback={`+${overflowCount}`}
            size={size}
            shape="circle"
            className={cn(ringClass, visibleItems.length > 0 && overlapClasses[size])}
            style={{ zIndex: visibleItems.length + 1 }}
          />
        ) : null}
      </div>
      {showCount ? (
        <span className={cn("text-(--avatar-group-label-fg)", labelSizeClasses[size])}>
          {memberCount} members
        </span>
      ) : null}
    </div>
  );
}

/* Avatar group component tokens — override these to customise avatar stacks. */
:root {
  --avatar-group-ring: var(--color-background);
  --avatar-group-ring-width: 2px;

  --avatar-group-overlap-xs: 2px;
  --avatar-group-overlap-sm: 4px;
  --avatar-group-overlap-md: 4px;
  --avatar-group-overlap-lg: 5px;
  --avatar-group-overlap-xl: 4px;
  --avatar-group-overlap-2xl: 6px;
  --avatar-group-overlap-3xl: 8px;

  --avatar-group-label-fg: var(--color-muted-foreground);

  --avatar-group-label-xs-font-size: 11px;
  --avatar-group-label-sm-font-size: 11px;
  --avatar-group-label-md-font-size: 14px;
  --avatar-group-label-lg-font-size: 14px;
  --avatar-group-label-xl-font-size: 16px;
  --avatar-group-label-2xl-font-size: 18px;
  --avatar-group-label-3xl-font-size: 20px;
}

import { ark } from "@ark-ui/react/factory";
import { cva, type VariantProps } from "class-variance-authority";
import type { ComponentPropsWithoutRef } from "react";
import { cn } from "@/lib/utils";

const buttonVariants = cva(
  "inline-flex cursor-pointer items-center justify-center gap-2 whitespace-nowrap font-medium transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-(--btn-ring) focus-visible:ring-offset-2 disabled:pointer-events-none disabled:opacity-(--btn-disabled-opacity) [&_svg]:pointer-events-none [&_svg]:shrink-0",
  {
    variants: {
      variant: {
        solid:
          "bg-(--btn-solid-bg) text-(--btn-solid-fg) hover:bg-(--btn-solid-bg-hover) [box-shadow:var(--btn-solid-shadow)]",
        outline:
          "border border-(--btn-outline-border) text-(--btn-outline-fg) hover:bg-(--btn-outline-bg-hover)",
        ghost:
          "text-(--btn-ghost-fg) hover:bg-(--btn-ghost-bg-hover)",
        link:
          "text-(--btn-link-fg) underline-offset-4 hover:underline",
      },
      size: {
        sm: "h-(--btn-sm-height) px-(--btn-sm-px) [font-size:var(--btn-sm-font-size)] rounded-(--btn-radius)",
        md: "h-(--btn-md-height) px-(--btn-md-px) [font-size:var(--btn-md-font-size)] rounded-(--btn-radius)",
        lg: "h-(--btn-lg-height) px-(--btn-lg-px) [font-size:var(--btn-lg-font-size)] rounded-(--btn-radius)",
      },
    },
    defaultVariants: {
      variant: "solid",
      size: "md",
    },
  },
);
export type ButtonProps = ComponentPropsWithoutRef<typeof ark.button> &
  VariantProps<typeof buttonVariants> & {
    asChild?: boolean;
  };
export function Button({
  className,
  variant,
  size,
  asChild = false,
  ...props
}: ButtonProps) {
  return (
    <ark.button
      asChild={asChild}
      className={cn(buttonVariants({ variant, size }), className)}
      {...props}
    />
  );
}

/* Button component tokens — override these to customise the button. */
:root {
  /* Solid variant */
  --btn-solid-bg: var(--color-primary);
  --btn-solid-fg: var(--color-primary-foreground);
  --btn-solid-bg-hover: oklch(from var(--color-primary) calc(l - 0.06) c h);
  /* visual-button-shadow-anatomy: six-layer shadow for depth and polish */
  --btn-solid-shadow:
    0 0 0 0.5px oklch(0 0 0 / 0.2), inset 0 0 0 1px oklch(1 1 1 / 0.04),
    inset 0 1px 0 oklch(1 1 1 / 0.07), 0 1px 2px oklch(0 0 0 / 0.1), 0 2px 4px oklch(0 0 0 / 0.06),
    0 4px 8px oklch(0 0 0 / 0.03);

  /* Outline variant */
  --btn-outline-border: var(--color-border);
  --btn-outline-fg: var(--color-foreground);
  --btn-outline-bg-hover: var(--color-accent);

  /* Ghost variant */
  --btn-ghost-fg: var(--color-foreground);
  --btn-ghost-bg-hover: var(--color-accent);

  /* Link variant */
  --btn-link-fg: var(--color-primary);

  /* Shared */
  --btn-radius: var(--radius-md);
  --btn-ring: var(--color-ring);
  --btn-disabled-opacity: 0.5;

  /* Size: sm */
  --btn-sm-height: 32px;
  --btn-sm-px: 12px;
  --btn-sm-font-size: 13px;

  /* Size: md */
  --btn-md-height: 36px;
  --btn-md-px: 16px;
  --btn-md-font-size: 14px;

  /* Size: lg */
  --btn-lg-height: 40px;
  --btn-lg-px: 20px;
  --btn-lg-font-size: 15px;
}

import { forwardRef } from "react";
import type { ComponentPropsWithoutRef } from "react";
import { cn } from "@/lib/utils";
export type LabelProps = ComponentPropsWithoutRef<"label"> & {
  disabled?: boolean;
};
export const Label = forwardRef<HTMLLabelElement, LabelProps>(
  ({ className, disabled, ...props }, ref) => {
    return (
      <label
        ref={ref}
        data-disabled={disabled || undefined}
        className={cn(
          "[font-size:var(--label-font-size)] font-(--label-font-weight) text-(--label-color) data-[disabled]:text-(--label-disabled-color) data-[disabled]:cursor-not-allowed",
          className,
        )}
        {...props}
      />
    );
  },
);

Label.displayName = "Label";
